--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -13345,6 +13345,15 @@ TTI::CastContextHint BoUpSLP::getCastContextHint(const TreeEntry &TE) const {
 InstructionCost
 BoUpSLP::getEntryCost(const TreeEntry *E, ArrayRef<Value *> VectorizedVals,
                       SmallPtrSetImpl<Value *> &CheckedExtracts) {
+  // If the entry is not used by another entry in the tree, it is not going to
+  // be vectorized.
+  if (!E->UserTreeIndex.isValid())
+    return InstructionCost::getInvalid();
+
+  // We have computed the cost of this node already.
+  if (E->Cost != InstructionCost::getInvalid())
+    return E->Cost;
+
   ArrayRef<Value *> VL = E->Scalars;

   Type *ScalarTy = getValueType(VL[0]);
